BEGIN TRANSACTION;

drop schema if exists "tour_musicali" cascade;

create schema "tour_musicali";
set search_path to "tour_musicali";

CREATE TABLE ARTISTA (
    nomeA VARCHAR(255) PRIMARY KEY,
    gruppo VARCHAR(255),
    genere VARCHAR(100),
    paese VARCHAR(100)
);

CREATE TABLE BRANO (
    branoId VARCHAR(50) PRIMARY KEY,
    titolo VARCHAR(255),
    durata INTEGER,
    album VARCHAR(255)
);

CREATE TABLE TOUR (
    titoloT VARCHAR(255) PRIMARY KEY,
    nome VARCHAR(255),
    dataInizio DATE,
    dataFine DATE,
    nomeA VARCHAR(255) REFERENCES ARTISTA(nomeA)
);

CREATE TABLE CONCERTO (
    concertoId VARCHAR(50) PRIMARY KEY,
    data DATE,
    citta VARCHAR(255),
    luogo VARCHAR(255),
    titoloT VARCHAR(255) REFERENCES TOUR(titoloT)
);

CREATE TABLE SCALETTA (
    concertoId VARCHAR(50) REFERENCES CONCERTO(concertoId),
    posizione INTEGER,
    branoId VARCHAR(50) REFERENCES BRANO(branoId),
    PRIMARY KEY (concertoId, posizione)
);

-- No INSERT statements (exam PDF source, no data instances provided)

COMMIT;
